import { useState } from 'react';
import { Link, useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import './StaticPages.css';

export function Services() {
  const services = [
    { icon:'ЁЯТЙ', title:'IV Therapy', desc:'Professional IV drip administration including fluids, vitamins, antibiotics, and medications at home by certified nurses.', price:'тВи1,500+' },
    { icon:'ЁЯй╣', title:'Wound Care & Dressing', desc:'Expert wound cleaning, dressing changes, post-surgical suture care, and pressure ulcer management.', price:'тВи800+' },
    { icon:'ЁЯТК', title:'Medication Administration', desc:'Supervised oral, IM, and IV medication administration with monitoring for side effects.', price:'тВи600+' },
    { icon:'ЁЯй╕', title:'Home Blood Tests', desc:'Professional sample collection for complete blood count, sugar, lipids, and all standard lab tests.', price:'тВи500+' },
    { icon:'ЁЯС╢', title:'Pediatric Nursing', desc:'Specialized care for children and newborns including vaccination support and pediatric assessments.', price:'тВи1,000+' },
    { icon:'ЁЯзУ', title:'Elderly Care', desc:'Full-time and part-time companion nursing, mobility assistance, and chronic condition management.', price:'тВи900+' },
    { icon:'ЁЯПе', title:'Post-Op Recovery', desc:'Professional post-operative monitoring, early mobilization, and recovery support at home.', price:'тВи1,200+' },
    { icon:'тЭдя╕П', title:'Vital Signs Monitoring', desc:'Regular blood pressure, oxygen, temperature, and pulse monitoring with detailed reports.', price:'тВи500+' },
  ];
  return (
    <div className="static-page">
      <h1 className="static-h1">Our Healthcare Services</h1>
      <p style={{color:'var(--muted)',fontSize:16,marginBottom:40}}>Professional medical care delivered to your home by certified nurses</p>
      <div className="services-grid">
        {services.map((s,i) => (
          <div key={i} className="card service-card">
            <div className="service-icon">{s.icon}</div>
            <div>
              <h3>{s.title}</h3>
              <p>{s.desc}</p>
              <div className="service-footer">
                <span style={{fontSize:13,fontWeight:700,color:'var(--teal)'}}>From {s.price}</span>
                <Link to="/nurses" className="btn btn-teal btn-sm">Book Now</Link>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export function About() {
  return (
    <div className="static-page">
      <h1 className="static-h1">About SehatSuhul</h1>
      <p style={{fontSize:16,color:'var(--muted)',lineHeight:1.8,marginBottom:24}}>
        SehatSuhul is Srinagar's leading home healthcare platform connecting patients with certified, verified nursing professionals. Our mission is to make quality healthcare accessible, affordable, and convenient for every household.
      </p>
